const s = {
  wrapper: {
    marginTop: 12,
    fontFamily: "system-ui, -apple-system, sans-serif",
  },

  button: {
    width: "100%",
    padding: "12px",
    borderRadius: 8,
    border: "1px solid var(--border)",
    background: "var(--bg-2)",
    fontWeight: 600,
    fontSize: "0.95rem",
    cursor: "pointer",
  },

  error: {
    marginTop: 10,
    padding: 10,
    background: "#fee2e2",
    borderRadius: 6,
    fontSize: "0.9rem",
    color: "#dc2626",
  },

  container: {
    marginTop: 16,
    border: "1px solid var(--border)",
    borderRadius: 12,
    padding: 18,
    background: "#fff",
    fontSize: "0.95rem",
    lineHeight: 1.6,
  },

  top: {
    display: "flex",
    justifyContent: "space-between",
    marginBottom: 16,
  },

  scoreBox: {
    display: "flex",
    flexDirection: "column",
    alignItems: "center",
    background: "var(--bg-2)",
    padding: "10px 14px",
    borderRadius: 8,
  },

  score: {
    fontSize: "1.5rem",
    fontWeight: 800,
  },

  scoreLabel: {
    fontSize: "0.8rem",
    color: "var(--muted)",
  },

  meta: {
    display: "flex",
    gap: 24,
  },

  metaItem: {
    display: "flex",
    flexDirection: "column",
    fontSize: "0.95rem",
  },

  block: {
    background: "var(--bg-2)",
    padding: 12,
    borderRadius: 8,
    marginBottom: 14,
  },

  blockTitle: {
    fontSize: "0.95rem",
    fontWeight: 700,
    marginBottom: 6,
  },

  blockText: {
    fontSize: "1rem",
    lineHeight: 1.7,
  },

  grid: {
    display: "grid",
    gridTemplateColumns: "1fr 1fr",
    gap: 18,
  },

  listItem: {
    fontSize: "0.95rem",
    marginBottom: 8,
    color: "var(--mid)",
    lineHeight: 1.6,
  },

  footer: {
    marginTop: 14,
    fontSize: "0.85rem",
    textAlign: "center",
    color: "var(--muted)",
  },
};
